previewCss:
.darma-loader-darma-custom-218 {
  color: var(--loader-color, #7c3aed);
height: 15px;
aspect-ratio: 4;
--_g: no-repeat radial-gradient(farthest-side,currentColor 90%,#0000);
background:
var(--_g) left,
var(--_g) right;
background-size: 25% 100%;
display: grid;
}
.darma-loader-darma-custom-218:before,
.darma-loader-darma-custom-218:after {
content: "";
height: inherit;
aspect-ratio: 1;
grid-area: 1/1;
margin: auto;
border-radius: 50%;
transform-origin: -100% 50%;
background: currentColor;
animation: darma-loader-darma-custom-218-l49 1s infinite linear;
}
.darma-loader-darma-custom-218:after {
transform-origin: 200% 50%;
--s:-1;
animation-delay: -.5s;
}

@keyframes darma-loader-darma-custom-218-l49 {
58%,
100% {transform: rotate(calc(var(--s,1)*1turn))}
}

